import { useState, useRef, useEffect } from "react";

const LOGO = "data:image/png;base64,";

const ZYNS = [
  { id:"coder", icon:"💻", name:"Zyn Coder", desc:"Expert coding assistant for any language", color:"#4488ff", system:"You are Zyn Coder, an expert programming assistant inside Zyncc. You excel at all programming languages — Python, JavaScript, TypeScript, React, CSS, HTML, SQL, Rust, Go, C++ and more. Write clean, well-commented code, explain what it does, and suggest improvements. Be concise and technical." },
  { id:"writer", icon:"✍️", name:"Zyn Writer", desc:"Creative writing, essays, stories & more", color:"#aa44ff", system:"You are Zyn Writer, a creative writing assistant inside Zyncc. You help with essays, stories, blog posts, poems, scripts, and any written content. You have a strong sense of narrative, voice, and style. Be imaginative and engaging." },
  { id:"tutor", icon:"📚", name:"Zyn Tutor", desc:"Learn anything with step-by-step explanations", color:"#ff9900", system:"You are Zyn Tutor, an educational assistant inside Zyncc. You explain complex topics simply, use analogies, examples, and step-by-step breakdowns. You adapt to the user's level and make learning fun and engaging." },
  { id:"chef", icon:"🍳", name:"Zyn Chef", desc:"Recipes, cooking tips & meal planning", color:"#ff5533", system:"You are Zyn Chef, a culinary assistant inside Zyncc. You know thousands of recipes, cooking techniques, ingredient substitutions, and meal planning strategies. Be enthusiastic about food and give practical, delicious advice." },
  { id:"fitness", icon:"💪", name:"Zyn Fit", desc:"Workout plans, nutrition & fitness advice", color:"#22cc88", system:"You are Zyn Fit, a fitness and nutrition assistant inside Zyncc. You create workout plans, give nutrition advice, explain exercises, and help users reach their fitness goals. Be motivating and science-based." },
  { id:"finance", icon:"📈", name:"Zyn Finance", desc:"Budgeting, investing & financial planning", color:"#44ddaa", system:"You are Zyn Finance, a personal finance assistant inside Zyncc. You help with budgeting, saving, investing basics, and financial planning. Always note you're not a licensed advisor. Be practical and clear." },
  { id:"therapist", icon:"🧠", name:"Zyn Mind", desc:"Mental wellness, mindfulness & support", color:"#ff66aa", system:"You are Zyn Mind, a mental wellness assistant inside Zyncc. You offer a supportive, non-judgmental space for reflection, mindfulness techniques, and emotional support. Always recommend professional help for serious issues. Be warm and empathetic." },
  { id:"travel", icon:"🌍", name:"Zyn Travel", desc:"Trip planning, destinations & travel tips", color:"#33aaff", system:"You are Zyn Travel, a travel planning assistant inside Zyncc. You know destinations worldwide, help plan itineraries, suggest hidden gems, and give practical travel tips. Be enthusiastic and detailed." },
  { id:"debug", icon:"🐛", name:"Zyn Debug", desc:"Find & fix bugs fast", color:"#ffaa00", system:"You are Zyn Debug, a debugging specialist inside Zyncc. You analyze code for bugs, explain why they occur, provide fixes, and suggest best practices to prevent future issues. Be systematic and precise." },
  { id:"resume", icon:"📄", name:"Zyn Resume", desc:"CVs, cover letters & job prep", color:"#8866ff", system:"You are Zyn Resume, a career assistant inside Zyncc. You help craft compelling resumes, cover letters, LinkedIn profiles, and prepare for job interviews. Be professional and tailored to the user's goals." },
  { id:"translate", icon:"🗣️", name:"Zyn Translate", desc:"Translate & learn any language", color:"#ff4488", system:"You are Zyn Translate, a language assistant inside Zyncc. You translate between any languages, explain grammar and idioms, and help users learn new languages. Be accurate and educational." },
  { id:"math", icon:"🧮", name:"Zyn Math", desc:"Math, stats & problem solving", color:"#00ccff", system:"You are Zyn Math, a mathematics assistant inside Zyncc. You solve math problems step-by-step, explain concepts clearly, and help with everything from basic arithmetic to calculus and statistics. Be precise and educational." },
];

const BASE_SYSTEM = `You are Zyncc, a helpful and friendly AI assistant. You have strong coding skills across all languages. Be concise and friendly. If someone says 'good boy', respond with exactly 'pup...' and nothing else.`;

function getUsers() { try { return JSON.parse(localStorage.getItem("zyncc_users")||"{}"); } catch { return {}; } }
function saveUsers(u) { localStorage.setItem("zyncc_users", JSON.stringify(u)); }
function getSession() { try { return JSON.parse(localStorage.getItem("zyncc_session")||"null"); } catch { return null; } }
function saveSession(u) { localStorage.setItem("zyncc_session", JSON.stringify(u)); }
function clearSession() { localStorage.removeItem("zyncc_session"); }

export default function ZynccAI() {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [sidebarTab, setSidebarTab] = useState("chats"); // "chats" | "zyns"
  const [modal, setModal] = useState(null);
  const [user, setUser] = useState(() => {
    const s = getSession();
    if (s && s.name && s.name === s.email) { clearSession(); return null; }
    return s;
  });
  const [formData, setFormData] = useState({ name:"", email:"", password:"" });
  const [formError, setFormError] = useState("");
  const [messages, setMessages] = useState([]);
  const [chatHistory, setChatHistory] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState("");
  const [view, setView] = useState("home");
  const [activeZyn, setActiveZyn] = useState(null);
  const [recording, setRecording] = useState(false);
  const [recSeconds, setRecSeconds] = useState(0);
  const [recLevel, setRecLevel] = useState(0);
  const [audioURL, setAudioURL] = useState(null);
  const [ctxMenu, setCtxMenu] = useState(null);
  const [theme, setTheme] = useState("dark");
  const [fontSize, setFontSize] = useState("md");
  const chatRef = useRef(null);
  const textareaRef = useRef(null);
  const recInterval = useRef(null);
  const mediaRecorder = useRef(null);
  const audioChunks = useRef([]);
  const analyserRef = useRef(null);
  const animFrameRef = useRef(null);
  const audioCtxRef = useRef(null);

  const themes = {
    dark:    { bg:"#0d0d0d", bg2:"#171717", bg3:"#1e1e1e", text:"#ececec", muted:"#666", muted2:"#999", accent:"#e8341a", accent2:"#c0336e" },
    midnight:{ bg:"#080810", bg2:"#0f0f1a", bg3:"#161625", text:"#e0e0ff", muted:"#556", muted2:"#88a", accent:"#6644ff", accent2:"#4488ff" },
    red:     { bg:"#100808", bg2:"#1a0f0f", bg3:"#221515", text:"#ffe0e0", muted:"#664", muted2:"#a88", accent:"#ff2222", accent2:"#ff6600" },
  };
  const C = themes[theme];
  const fSize = { sm:13, md:14.5, lg:16 }[fontSize];

  function extractFirstName(n) {
    if (!n) return null;
    if (n.includes("@")) return n.split("@")[0].replace(/[0-9]/g,"").replace(/[._-]/g," ").trim().split(" ")[0];
    return n.split(" ")[0];
  }
  const firstName = user ? extractFirstName(user.name) : null;
  const displayName = firstName ? firstName.charAt(0).toUpperCase() + firstName.slice(1) : null;

  useEffect(() => {
    function onCtx(e) { e.preventDefault(); setCtxMenu({ x:e.clientX, y:e.clientY }); }
    function onClose() { setCtxMenu(null); }
    window.addEventListener("contextmenu", onCtx);
    window.addEventListener("click", onClose);
    return () => { window.removeEventListener("contextmenu", onCtx); window.removeEventListener("click", onClose); };
  }, []);

  async function toggleRecording() {
    if (recording) {
      // STOP
      mediaRecorder.current?.stop();
      clearInterval(recInterval.current);
      cancelAnimationFrame(animFrameRef.current);
      audioCtxRef.current?.close();
      setRecording(false); setRecSeconds(0); setRecLevel(0);
    } else {
      // START
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
        // set up analyser for waveform
        const audioCtx = new AudioContext();
        audioCtxRef.current = audioCtx;
        const source = audioCtx.createMediaStreamSource(stream);
        const analyser = audioCtx.createAnalyser();
        analyser.fftSize = 256;
        source.connect(analyser);
        analyserRef.current = analyser;
        const dataArr = new Uint8Array(analyser.frequencyBinCount);
        function tick() {
          analyser.getByteFrequencyData(dataArr);
          const avg = dataArr.reduce((a,b) => a+b, 0) / dataArr.length;
          setRecLevel(avg / 128);
          animFrameRef.current = requestAnimationFrame(tick);
        }
        tick();

        // set up MediaRecorder
        audioChunks.current = [];
        const mr = new MediaRecorder(stream);
        mediaRecorder.current = mr;
        mr.ondataavailable = e => { if (e.data.size > 0) audioChunks.current.push(e.data); };
        mr.onstop = () => {
          const blob = new Blob(audioChunks.current, { type:"audio/webm" });
          const url = URL.createObjectURL(blob);
          setAudioURL(url);
          stream.getTracks().forEach(t => t.stop());
          setToast("Recording saved! ▶ Play it below");
        };
        mr.start();
        setRecording(true); setRecSeconds(0); setAudioURL(null);
        recInterval.current = setInterval(() => setRecSeconds(s => s+1), 1000);
      } catch(err) {
        setToast("Mic access denied 🎤");
      }
    }
  }
  useEffect(() => () => {
    clearInterval(recInterval.current);
    cancelAnimationFrame(animFrameRef.current);
    audioCtxRef.current?.close();
  }, []);
  function fmtTime(s) { return `${String(Math.floor(s/60)).padStart(2,"0")}:${String(s%60).padStart(2,"0")}`; }

  useEffect(() => { if (chatRef.current) chatRef.current.scrollTop = chatRef.current.scrollHeight; }, [messages, loading]);
  useEffect(() => { if (toast) { const t = setTimeout(() => setToast(""), 2500); return () => clearTimeout(t); } }, [toast]);

  function handleSignIn() {
    setFormError("");
    const users = getUsers();
    const found = users[formData.email.toLowerCase()];
    if (!found) { setFormError("No account found."); return; }
    if (found.password !== formData.password) { setFormError("Wrong password."); return; }
    const s = { name:found.name, email:found.email };
    saveSession(s); setUser(s); setModal(null); setFormData({ name:"", email:"", password:"" });
    setToast("Welcome back, " + found.name + "! 👋");
  }

  function handleSignUp() {
    setFormError("");
    if (!formData.name.trim()) { setFormError("Name is required."); return; }
    if (formData.name.includes("@")) { setFormError("That's an email, not a name!"); return; }
    if (!formData.email.includes("@")) { setFormError("Enter a valid email."); return; }
    if (formData.password.length < 6) { setFormError("Password needs 6+ characters."); return; }
    const users = getUsers();
    if (users[formData.email.toLowerCase()]) { setFormError("Account exists. Sign in instead."); return; }
    users[formData.email.toLowerCase()] = { name:formData.name.trim(), email:formData.email.toLowerCase(), password:formData.password };
    saveUsers(users);
    const s = { name:formData.name.trim(), email:formData.email.toLowerCase() };
    saveSession(s); setUser(s); setModal(null); setFormData({ name:"", email:"", password:"" });
    setToast("Welcome, " + formData.name.trim() + " 🎉");
  }

  function handleSignOut() { clearSession(); setUser(null); setToast("Signed out."); setSidebarOpen(false); }

  function newChat() {
    if (messages.length > 0) {
      const title = (activeZyn ? activeZyn.icon + " " : "") + messages[0].content.slice(0,38) + (messages[0].content.length > 38 ? "..." : "");
      setChatHistory(h => [{ title, messages:[...messages], zyn:activeZyn }, ...h]);
    }
    setMessages([]); setView("home"); setSidebarOpen(false); setActiveZyn(null);
  }

  function loadChat(i) { setMessages([...chatHistory[i].messages]); setActiveZyn(chatHistory[i].zyn||null); setView("chat"); setSidebarOpen(false); }
  function clearHistory() { setChatHistory([]); setToast("History cleared"); }

  function launchZyn(zyn) {
    newChat();
    setActiveZyn(zyn);
    setView("home");
    setSidebarOpen(false);
    setToast(`${zyn.icon} ${zyn.name} activated!`);
  }

  async function sendMessage() {
    const text = input.trim();
    if (loading || !text) return;
    const newMsgs = [...messages, { role:"user", content:text }];
    setMessages(newMsgs); setInput(""); setView("chat"); setLoading(true);
    if (textareaRef.current) { textareaRef.current.value = ""; textareaRef.current.style.height = "50px"; }
    try {
      const systemPrompt = activeZyn ? activeZyn.system : BASE_SYSTEM;
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ model:"claude-sonnet-4-20250514", max_tokens:2000, system:systemPrompt, messages:newMsgs.map(m=>({role:m.role,content:m.content})) })
      });
      const data = await res.json();
      if (data.content?.[0]?.text) {
        setMessages([...newMsgs, { role:"assistant", content:data.content[0].text }]);
      } else { setToast("Something went wrong."); setMessages(messages); }
    } catch { setToast("Network error."); setMessages(messages); }
    setLoading(false);
  }

  function handleKeyDown(e) { if (e.key==="Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } }
  function handleTextarea(e) {
    const el = e.target; el.style.height = "50px";
    el.style.height = Math.min(el.scrollHeight, 160) + "px"; setInput(el.value);
  }
  function chipClick(c) {
    const txt = c.replace(/^\S+\s/, "");
    setInput(txt);
    if (textareaRef.current) { textareaRef.current.value = txt; textareaRef.current.style.height = "50px"; textareaRef.current.focus(); }
  }

  function renderContent(text) {
    const urlRegex = /(https?:\/\/[^\s<>"')\]]+)/g;
    const parts = text.split(urlRegex);
    return parts.flatMap((part, i) => {
      if (/^https?:\/\//.test(part)) {
        return [<a key={`u${i}`} href={part} target="_blank" rel="noopener noreferrer"
          style={{color:C.accent,textDecoration:"underline",wordBreak:"break-all"}}>{part}</a>];
      }
      return part.split(/(\*\*[^*]+\*\*|`[^`]+`)/g).map((chunk, j) => {
        if (chunk.startsWith("**") && chunk.endsWith("**")) return <strong key={`b${i}${j}`}>{chunk.slice(2,-2)}</strong>;
        if (chunk.startsWith("`") && chunk.endsWith("`")) return <code key={`c${i}${j}`} style={{background:C.bg3,padding:"1px 5px",borderRadius:4,fontFamily:"monospace",fontSize:"0.88em",color:"#ff9966"}}>{chunk.slice(1,-1)}</code>;
        return <span key={`t${i}${j}`}>{chunk}</span>;
      });
    });
  }

  const chips = activeZyn ? [] : ["✍️ Write something","💡 Brainstorm ideas","🔍 Explain a concept","💻 Help with code","📋 Summarize text","🌍 Translate text","🐛 Debug my code","📊 Analyze data","🧮 Math & logic"];
  const inputActive = !!input.trim() && !loading;

  const mInput = { width:"100%", background:C.bg3, border:"1px solid rgba(255,255,255,0.08)", borderRadius:10, padding:"12px 14px", color:C.text, fontFamily:"inherit", fontSize:14, outline:"none", marginBottom:10, display:"block" };
  const mBtn = { width:"100%", padding:12, background:`linear-gradient(135deg,${C.accent},${C.accent2})`, border:"none", borderRadius:10, color:"white", fontFamily:"inherit", fontSize:14, fontWeight:500, cursor:"pointer", marginTop:4 };
  const gBtn = { width:"100%", padding:11, background:C.bg3, border:"1px solid rgba(255,255,255,0.08)", borderRadius:10, color:C.text, fontFamily:"inherit", fontSize:14, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center", gap:10, marginTop:8 };

  function ModalShell({ onClose, children }) {
    return (
      <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",zIndex:100,display:"flex",alignItems:"center",justifyContent:"center"}}
        onClick={e=>{if(e.target===e.currentTarget){onClose();setFormError("");}}}>
        <div style={{background:C.bg2,border:"1px solid rgba(255,255,255,0.08)",borderRadius:20,padding:"36px 32px",width:"100%",maxWidth:360,display:"flex",flexDirection:"column",alignItems:"center",position:"relative",boxShadow:"0 24px 80px rgba(0,0,0,0.6)"}}>
          <button onClick={()=>{onClose();setFormError("");}} style={{position:"absolute",top:12,right:12,background:"none",border:"none",cursor:"pointer",color:C.muted,fontSize:22,lineHeight:1,padding:"2px 8px"}}>×</button>
          {children}
        </div>
      </div>
    );
  }

  const modalLogo = <img src={LOGO} alt="Z" style={{width:48,height:48,marginBottom:10,filter:`drop-shadow(0 0 14px ${C.accent}88)`}}/>;
  const modalTitle = t => <div style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:21,background:`linear-gradient(135deg,${C.text},${C.accent},${C.accent2})`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",marginBottom:4}}>{t}</div>;
  const divider = <div style={{width:"100%",display:"flex",alignItems:"center",gap:10,margin:"14px 0 0",color:C.muted,fontSize:12}}><div style={{flex:1,height:1,background:"rgba(255,255,255,0.08)"}}/>or<div style={{flex:1,height:1,background:"rgba(255,255,255,0.08)"}}/></div>;

  function GoogleBtn({ onClick }) {
    return <button style={gBtn} onClick={onClick}>
      <svg width="16" height="16" viewBox="0 0 24 24"><path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/><path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/><path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/><path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/></svg>
      Continue with Google
    </button>;
  }

  const ctxItems = [
    { icon:"✏️", label:"New Chat", action:()=>{ newChat(); setCtxMenu(null); } },
    { icon:"🌑", label:"Dark theme", action:()=>{ setTheme("dark"); setCtxMenu(null); setToast("Dark 🌑"); } },
    { icon:"🌌", label:"Midnight theme", action:()=>{ setTheme("midnight"); setCtxMenu(null); setToast("Midnight 🌌"); } },
    { icon:"🔴", label:"Red theme", action:()=>{ setTheme("red"); setCtxMenu(null); setToast("Red 🔴"); } },
    { divider:true },
    { icon:"🔡", label:"Small text", action:()=>{ setFontSize("sm"); setCtxMenu(null); } },
    { icon:"🔤", label:"Medium text", action:()=>{ setFontSize("md"); setCtxMenu(null); } },
    { icon:"🅰️", label:"Large text", action:()=>{ setFontSize("lg"); setCtxMenu(null); } },
    { divider:true },
    { icon:"🗑️", label:"Clear history", action:()=>{ clearHistory(); setCtxMenu(null); } },
    { icon:"🎙️", label:recording?"Stop recording":"Start recording", action:()=>{ toggleRecording(); setCtxMenu(null); } },
    { divider:true },
    { icon:"👤", label:user?"Sign out":"Sign in", action:()=>{ user?handleSignOut():setModal("signin"); setCtxMenu(null); } },
  ];

  return (
    <div style={{background:C.bg,color:C.text,height:"100vh",overflow:"hidden",fontFamily:"'DM Sans',sans-serif",display:"flex",flexDirection:"column",fontSize:fSize}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@800&family=DM+Sans:wght@300;400;500&display=swap');
        @keyframes bounce{0%,80%,100%{transform:translateY(0);opacity:.4}40%{transform:translateY(-5px);opacity:1}}
        @keyframes recPulse{0%,100%{opacity:1}50%{opacity:0.2}}
        @keyframes ctxIn{from{opacity:0;transform:scale(0.95) translateY(-4px)}to{opacity:1;transform:scale(1) translateY(0)}}
        @keyframes slideIn{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        *{box-sizing:border-box}
        ::-webkit-scrollbar{width:4px}
        ::-webkit-scrollbar-thumb{background:#2a2a2a;border-radius:4px}
        textarea::placeholder,input::placeholder{color:#555 !important}
        a{cursor:pointer}
      `}</style>

      {/* CONTEXT MENU */}
      {ctxMenu && (
        <div style={{position:"fixed",left:Math.min(ctxMenu.x,window.innerWidth-200),top:Math.min(ctxMenu.y,window.innerHeight-380),zIndex:500,background:C.bg2,border:"1px solid rgba(255,255,255,0.1)",borderRadius:12,padding:"6px",minWidth:190,boxShadow:"0 8px 32px rgba(0,0,0,0.6)",animation:"ctxIn 0.12s ease"}}>
          {ctxItems.map((item,i) => item.divider
            ? <div key={i} style={{height:1,background:"rgba(255,255,255,0.07)",margin:"4px 0"}}/>
            : <div key={i} onClick={item.action}
                style={{display:"flex",alignItems:"center",gap:9,padding:"8px 12px",borderRadius:8,cursor:"pointer",fontSize:13,color:C.text}}
                onMouseEnter={e=>e.currentTarget.style.background=C.bg3}
                onMouseLeave={e=>e.currentTarget.style.background="none"}>
                <span style={{fontSize:15}}>{item.icon}</span>{item.label}
              </div>
          )}
        </div>
      )}

      {sidebarOpen && <div onClick={()=>setSidebarOpen(false)} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:19}}/>}

      {/* SIDEBAR */}
      <div style={{position:"fixed",left:0,top:0,bottom:0,width:270,background:C.bg2,borderRight:"1px solid rgba(255,255,255,0.08)",display:"flex",flexDirection:"column",zIndex:20,transform:sidebarOpen?"translateX(0)":"translateX(-100%)",transition:"transform 0.28s cubic-bezier(0.4,0,0.2,1)"}}>

        {/* SIDEBAR HEADER */}
        <div style={{padding:"14px 12px 0",display:"flex",alignItems:"center",gap:6}}>
          <button onClick={()=>setSidebarOpen(false)} style={{background:"none",border:"none",cursor:"pointer",color:C.muted2,padding:6,borderRadius:6,display:"flex"}}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
          </button>
          <button onClick={newChat} style={{flex:1,background:"none",border:"none",cursor:"pointer",color:C.muted2,padding:"6px 10px",borderRadius:8,fontFamily:"inherit",fontSize:13.5,display:"flex",alignItems:"center",gap:8}}>
            <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
            New chat
          </button>
        </div>

        {/* TABS */}
        <div style={{display:"flex",margin:"10px 12px 0",background:C.bg3,borderRadius:10,padding:3,gap:2}}>
          {[["chats","💬 Chats"],["zyns","⚡ Zyns"]].map(([id,label])=>(
            <button key={id} onClick={()=>setSidebarTab(id)}
              style={{flex:1,padding:"7px 0",borderRadius:8,border:"none",cursor:"pointer",fontFamily:"inherit",fontSize:12.5,fontWeight:500,background:sidebarTab===id?C.bg2:"none",color:sidebarTab===id?C.text:C.muted,transition:"all 0.15s"}}>
              {label}
            </button>
          ))}
        </div>

        {/* CHATS TAB */}
        {sidebarTab==="chats" && (
          <>
            <div style={{padding:"10px 12px",borderBottom:"1px solid rgba(255,255,255,0.08)"}}>
              <input style={{width:"100%",background:C.bg3,border:"1px solid rgba(255,255,255,0.08)",borderRadius:8,padding:"8px 12px",color:C.text,fontFamily:"inherit",fontSize:13,outline:"none"}} placeholder="Search chats..."/>
            </div>
            <div style={{flex:1,overflowY:"auto",padding:"12px 12px 4px"}}>
              <div style={{fontSize:11,textTransform:"uppercase",letterSpacing:"1.2px",color:C.muted,marginBottom:6}}>Today</div>
              {chatHistory.length===0
                ? <div style={{padding:"8px 4px",fontSize:12.5,color:C.muted}}>No chats yet</div>
                : chatHistory.map((h,i)=>(
                  <div key={i} onClick={()=>loadChat(i)} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 10px",borderRadius:8,cursor:"pointer",fontSize:13.5,color:C.muted2,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}
                    onMouseEnter={e=>e.currentTarget.style.background=C.bg3} onMouseLeave={e=>e.currentTarget.style.background="none"}>
                    <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" style={{flexShrink:0}}><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
                    {h.title}
                  </div>
                ))}
            </div>
            <button onClick={clearHistory} style={{margin:"8px 12px 0",background:"none",border:"1px solid rgba(255,255,255,0.08)",borderRadius:8,color:C.muted,padding:"8px 12px",fontFamily:"inherit",fontSize:12.5,cursor:"pointer",width:"calc(100% - 24px)",display:"flex",alignItems:"center",justifyContent:"center",gap:7}}>
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14H6L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4h6v2"/></svg>
              Clear history
            </button>
          </>
        )}

        {/* ZYNS TAB */}
        {sidebarTab==="zyns" && (
          <div style={{flex:1,overflowY:"auto",padding:"10px 10px 4px"}}>
            <p style={{fontSize:12,color:C.muted,padding:"0 4px 10px",margin:0,lineHeight:1.5}}>Specialized Zyns for every task. Click one to start chatting.</p>
            <div style={{display:"flex",flexDirection:"column",gap:6}}>
              {ZYNS.map(zyn=>(
                <div key={zyn.id} onClick={()=>launchZyn(zyn)}
                  style={{display:"flex",alignItems:"center",gap:10,padding:"10px 10px",borderRadius:10,cursor:"pointer",border:`1px solid ${activeZyn?.id===zyn.id ? zyn.color+"55" : "rgba(255,255,255,0.06)"}`,background:activeZyn?.id===zyn.id?`${zyn.color}12`:"none",transition:"all 0.15s"}}
                  onMouseEnter={e=>{e.currentTarget.style.background=`${zyn.color}18`;e.currentTarget.style.borderColor=`${zyn.color}44`;}}
                  onMouseLeave={e=>{e.currentTarget.style.background=activeZyn?.id===zyn.id?`${zyn.color}12`:"none";e.currentTarget.style.borderColor=activeZyn?.id===zyn.id?`${zyn.color}55`:"rgba(255,255,255,0.06)";}}>
                  <div style={{width:36,height:36,borderRadius:10,background:`${zyn.color}22`,border:`1px solid ${zyn.color}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>{zyn.icon}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,fontWeight:500,color:C.text,display:"flex",alignItems:"center",gap:6}}>
                      {zyn.name}
                      {activeZyn?.id===zyn.id && <span style={{fontSize:9,background:zyn.color,color:"white",padding:"1px 6px",borderRadius:10,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.5px"}}>Active</span>}
                    </div>
                    <div style={{fontSize:11.5,color:C.muted,marginTop:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{zyn.desc}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* USER SECTION */}
        <div style={{padding:12,borderTop:"1px solid rgba(255,255,255,0.08)"}}>
          {user ? (
            <div>
              <div style={{display:"flex",alignItems:"center",gap:10,padding:"8px 10px"}}>
                <div style={{width:32,height:32,borderRadius:"50%",background:`linear-gradient(135deg,${C.accent},${C.accent2})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:600,color:"white",flexShrink:0}}>{(displayName||"?")[0].toUpperCase()}</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:13,fontWeight:500,color:C.text,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{displayName}</div>
                  <div style={{fontSize:11,color:C.muted,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{user.email}</div>
                </div>
              </div>
              <button onClick={handleSignOut} style={{width:"100%",marginTop:6,background:"none",border:"1px solid rgba(255,255,255,0.08)",borderRadius:8,color:"#888",padding:"7px 12px",fontFamily:"inherit",fontSize:12.5,cursor:"pointer"}}>Sign out</button>
            </div>
          ) : (
            <div onClick={()=>{setSidebarOpen(false);setModal("signin");}} style={{display:"flex",alignItems:"center",gap:10,padding:"8px 10px",borderRadius:10,cursor:"pointer"}}
              onMouseEnter={e=>e.currentTarget.style.background=C.bg3} onMouseLeave={e=>e.currentTarget.style.background="none"}>
              <div style={{width:32,height:32,borderRadius:"50%",background:`linear-gradient(135deg,${C.accent},${C.accent2})`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:13,fontWeight:600,color:"white",flexShrink:0}}>Z</div>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:500,color:C.text}}>Guest User</div>
                <div style={{fontSize:11,color:C.muted}}>Sign in to save chats</div>
              </div>
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={C.muted} strokeWidth="2"><polyline points="9 18 15 12 9 6"/></svg>
            </div>
          )}
        </div>
      </div>

      {/* TOPBAR */}
      <div style={{position:"fixed",top:0,left:0,right:0,height:52,display:"flex",alignItems:"center",padding:"0 16px",zIndex:10,background:C.bg,borderBottom:"1px solid rgba(255,255,255,0.08)",gap:8,flexShrink:0}}>
        <button onClick={()=>setSidebarOpen(o=>!o)} style={{background:"none",border:"none",cursor:"pointer",color:C.muted2,padding:6,borderRadius:6,display:"flex",flexDirection:"column",gap:4,flexShrink:0}}>
          {[0,1,2].map(i=><span key={i} style={{display:"block",width:17,height:1.5,background:"currentColor",borderRadius:2}}/>)}
        </button>
        <div onClick={newChat} style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",flexShrink:0}}>
          <img src={LOGO} alt="Zyncc" style={{width:26,height:26,filter:`drop-shadow(0 0 8px ${C.accent}88)`}}/>
          <span style={{fontFamily:"'Syne',sans-serif",fontWeight:800,fontSize:17,color:C.text,whiteSpace:"nowrap"}}>Zyncc</span>
        </div>
        {activeZyn && (
          <div style={{display:"flex",alignItems:"center",gap:6,background:`${activeZyn.color}18`,border:`1px solid ${activeZyn.color}44`,borderRadius:20,padding:"4px 10px",fontSize:12,color:activeZyn.color,fontWeight:500,flexShrink:0}}>
            {activeZyn.icon} {activeZyn.name}
            <button onClick={()=>{setActiveZyn(null);newChat();}} style={{background:"none",border:"none",cursor:"pointer",color:activeZyn.color,fontSize:14,lineHeight:1,padding:"0 0 0 4px",opacity:0.7}}>×</button>
          </div>
        )}
        <div style={{marginLeft:"auto",flexShrink:0}}>
          {user
            ? <span style={{fontSize:13,color:C.muted2}}>Hey, {displayName} 👋</span>
            : <button onClick={()=>setModal("signin")} style={{background:`linear-gradient(135deg,${C.accent},${C.accent2})`,border:"none",borderRadius:8,padding:"7px 16px",color:"white",fontFamily:"inherit",fontSize:13,fontWeight:500,cursor:"pointer"}}>Sign in</button>
          }
        </div>
      </div>

      {/* MAIN */}
      <div style={{flex:1,display:"flex",flexDirection:"column",paddingTop:52,paddingBottom:76,overflow:"hidden"}}>
        {view==="home" && (
          <div style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"40px 20px 20px",overflowY:"auto"}}>
            {activeZyn ? (
              <div style={{textAlign:"center",marginBottom:32,animation:"slideIn 0.3s ease"}}>
                <div style={{width:72,height:72,borderRadius:20,background:`${activeZyn.color}22`,border:`2px solid ${activeZyn.color}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:32,margin:"0 auto 16px"}}>
                  {activeZyn.icon}
                </div>
                <h1 style={{fontFamily:"'Syne',sans-serif",fontSize:28,fontWeight:800,color:C.text,letterSpacing:"-0.8px",margin:"0 0 8px 0"}}>{activeZyn.name}</h1>
                <p style={{fontSize:14,color:C.muted,margin:0}}>{activeZyn.desc}</p>
              </div>
            ) : (
              <div style={{textAlign:"center",marginBottom:32}}>
                <img src={LOGO} alt="Zyncc" style={{width:64,height:64,display:"block",margin:"0 auto 16px",filter:`drop-shadow(0 0 20px ${C.accent}aa)`}}/>
                <h1 style={{fontFamily:"'Syne',sans-serif",fontSize:32,fontWeight:800,color:C.text,letterSpacing:"-0.8px",margin:"0 0 8px 0"}}>
                  {user ? `What's up, ${displayName}?` : "What's on your mind?"}
                </h1>
                <p style={{fontSize:14,color:C.muted,margin:0}}>Ask anything. Right-click for more options.</p>
              </div>
            )}
            {chips.length > 0 && (
              <div style={{display:"flex",flexWrap:"wrap",gap:8,justifyContent:"center",maxWidth:560}}>
                {chips.map(c=>(
                  <button key={c} onClick={()=>chipClick(c)}
                    style={{background:C.bg2,border:"1px solid rgba(255,255,255,0.08)",color:C.muted2,borderRadius:20,padding:"7px 14px",fontSize:12.5,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}
                    onMouseEnter={e=>{e.currentTarget.style.background=`${C.accent}18`;e.currentTarget.style.color=C.text;}}
                    onMouseLeave={e=>{e.currentTarget.style.background=C.bg2;e.currentTarget.style.color=C.muted2;}}>
                    {c}
                  </button>
                ))}
              </div>
            )}
          </div>
        )}
        {view==="chat" && (
          <div ref={chatRef} style={{flex:1,overflowY:"auto",width:"100%",maxWidth:720,margin:"0 auto",padding:"24px 20px 20px",display:"flex",flexDirection:"column"}}>
            {messages.map((m,i)=>(
              <div key={i} style={{display:"flex",gap:12,marginBottom:24,flexDirection:m.role==="user"?"row-reverse":"row"}}>
                <div style={{width:30,height:30,borderRadius:activeZyn&&m.role==="assistant"?10:"50%",flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:m.role==="assistant"&&activeZyn?16:12,fontWeight:600,background:m.role==="user"?`linear-gradient(135deg,${C.accent},${C.accent2})`:activeZyn?`${activeZyn.color}22`:C.bg3,border:m.role!=="user"?`1px solid ${activeZyn?activeZyn.color+"44":"rgba(255,255,255,0.08)"}` :"none",color:"white",overflow:"hidden"}}>
                  {m.role==="user" ? (displayName?displayName[0].toUpperCase():"U") : activeZyn ? activeZyn.icon : <img src={LOGO} alt="Z" style={{width:18,height:18}}/>}
                </div>
                <div style={{maxWidth:"75%",display:m.role==="user"?"flex":"block",justifyContent:"flex-end"}}>
                  <div style={{padding:"11px 15px",borderRadius:14,fontSize:fSize,lineHeight:1.65,whiteSpace:"pre-wrap",wordBreak:"break-word",background:m.role==="user"?`${C.accent}22`:C.bg2,border:m.role==="user"?`1px solid ${C.accent}33`:"1px solid rgba(255,255,255,0.08)",borderBottomRightRadius:m.role==="user"?4:14,borderBottomLeftRadius:m.role==="assistant"?4:14,color:C.text}}>
                    {renderContent(m.content)}
                  </div>
                </div>
              </div>
            ))}
            {loading && (
              <div style={{display:"flex",gap:12,marginBottom:24}}>
                <div style={{width:30,height:30,borderRadius:activeZyn?10:"50%",flexShrink:0,background:activeZyn?`${activeZyn.color}22`:C.bg3,border:`1px solid ${activeZyn?activeZyn.color+"44":"rgba(255,255,255,0.08)"}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:activeZyn?16:12,overflow:"hidden"}}>
                  {activeZyn ? activeZyn.icon : <img src={LOGO} alt="Z" style={{width:18,height:18}}/>}
                </div>
                <div style={{padding:"14px 16px",background:C.bg2,border:"1px solid rgba(255,255,255,0.08)",borderRadius:14,borderBottomLeftRadius:4,display:"flex",gap:5,alignItems:"center"}}>
                  {[0,0.2,0.4].map((d,i)=><div key={i} style={{width:6,height:6,borderRadius:"50%",background:C.muted,animation:`bounce 1.2s ${d}s infinite`}}/>)}
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* INPUT */}
      <div style={{position:"fixed",bottom:0,left:0,right:0,padding:"10px 20px 14px",background:`linear-gradient(to top,${C.bg} 60%,transparent)`,zIndex:5,display:"flex",flexDirection:"column",alignItems:"center"}}>
        <div style={{width:"100%",maxWidth:680,position:"relative"}}>
          <textarea ref={textareaRef} value={input} onChange={handleTextarea} onKeyDown={handleKeyDown}
            placeholder={activeZyn ? `Message ${activeZyn.name}...` : "Message Zyncc..."}
            rows={1} style={{width:"100%",background:C.bg2,border:`1px solid ${recording?"rgba(255,50,50,0.5)":activeZyn?activeZyn.color+"44":"rgba(255,255,255,0.12)"}`,borderRadius:14,padding:"13px 90px 13px 16px",color:C.text,fontFamily:"inherit",fontSize:fSize,outline:"none",resize:"none",lineHeight:1.5,minHeight:50,maxHeight:160,display:"block",transition:"border-color 0.2s"}}/>

          {/* MIC BUTTON */}
          <button onClick={toggleRecording} title={recording?"Stop recording":"Start recording"}
            style={{position:"absolute",right:49,top:"50%",transform:"translateY(-50%)",width:32,height:32,borderRadius:8,background:recording?"rgba(255,40,40,0.15)":"rgba(255,255,255,0.06)",border:recording?"1px solid rgba(255,50,50,0.5)":"1px solid rgba(255,255,255,0.1)",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",padding:0,flexShrink:0,transition:"all 0.2s"}}>
            {recording ? (
              <div style={{display:"flex",alignItems:"center",gap:1.5}}>
                {Array.from({length:4}).map((_,i)=>(
                  <div key={i} style={{width:2.5,borderRadius:2,background:"#ff4444",height:Math.max(4,Math.round(recLevel*18*Math.abs(Math.sin(i*0.9+Date.now()/200))+4)),transition:"height 0.06s"}}/>
                ))}
              </div>
            ) : (
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={C.muted2} strokeWidth="2" strokeLinecap="round"><rect x="9" y="2" width="6" height="12" rx="3"/><path d="M5 10a7 7 0 0 0 14 0"/><line x1="12" y1="19" x2="12" y2="22"/><line x1="9" y1="22" x2="15" y2="22"/></svg>
            )}
          </button>

          {/* SEND BUTTON */}
          <button onClick={sendMessage}
            style={{position:"absolute",right:9,top:"50%",transform:"translateY(-50%)",width:32,height:32,borderRadius:8,background:activeZyn?`linear-gradient(135deg,${activeZyn.color},${activeZyn.color}aa)`:`linear-gradient(135deg,${C.accent},${C.accent2})`,border:"none",cursor:inputActive?"pointer":"default",display:"flex",alignItems:"center",justifyContent:"center",opacity:inputActive?1:0.3,transition:"opacity 0.2s",padding:0,flexShrink:0}}>
            <svg viewBox="0 0 24 24" width="13" height="13" style={{fill:"white",display:"block"}}><path d="M2 12L22 2L12 22L10 14L2 12Z"/></svg>
          </button>
        </div>

        {/* RECORDING STATUS / AUDIO PLAYER */}
        {(recording || audioURL) && (
          <div style={{width:"100%",maxWidth:680,marginTop:8,display:"flex",alignItems:"center",gap:10,padding:"8px 14px",background:C.bg2,border:`1px solid ${recording?"rgba(255,50,50,0.3)":"rgba(255,255,255,0.08)"}`,borderRadius:10}}>
            {recording ? (
              <>
                <div style={{width:8,height:8,borderRadius:"50%",background:"#ff3333",animation:"recPulse 1s ease infinite",flexShrink:0}}/>
                <span style={{fontSize:12,color:"#ff4444",fontWeight:600}}>REC</span>
                <span style={{fontSize:12,color:"#ff6666",fontFamily:"monospace"}}>{fmtTime(recSeconds)}</span>
                <div style={{flex:1,display:"flex",alignItems:"center",gap:2}}>
                  {Array.from({length:20}).map((_,i)=>(
                    <div key={i} style={{flex:1,borderRadius:2,background:"#ff4444",opacity:0.7,height:Math.max(2,Math.round(recLevel*20*Math.abs(Math.sin(i*0.5))+2)),transition:"height 0.08s"}}/>
                  ))}
                </div>
                <button onClick={toggleRecording} style={{background:"none",border:"1px solid rgba(255,50,50,0.4)",borderRadius:6,color:"#ff4444",padding:"3px 10px",fontSize:12,cursor:"pointer",fontFamily:"inherit",flexShrink:0}}>Stop ■</button>
              </>
            ) : (
              <>
                <span style={{fontSize:12,color:C.muted,flexShrink:0}}>🎙️ Recording</span>
                <audio controls src={audioURL} style={{flex:1,height:28,minWidth:0,accentColor:C.accent}}/>
                <button onClick={()=>setAudioURL(null)} style={{background:"none",border:"none",cursor:"pointer",color:C.muted,fontSize:16,lineHeight:1,padding:"0 2px",flexShrink:0}}>×</button>
              </>
            )}
          </div>
        )}

        <p style={{fontSize:11,color:"#3a3a3a",marginTop:5,textAlign:"center"}}>Zyncc can make mistakes · Right-click for options</p>
      </div>

      {/* SIGN IN */}
      {modal==="signin" && (
        <ModalShell onClose={()=>setModal(null)}>
          {modalLogo}{modalTitle("Welcome back")}
          <p style={{fontSize:13,color:C.muted,marginBottom:20}}>Sign in to your Zyncc account</p>
          <input type="email" placeholder="Email address" style={mInput} value={formData.email} onChange={e=>setFormData(f=>({...f,email:e.target.value}))}/>
          <input type="password" placeholder="Password" style={mInput} value={formData.password} onChange={e=>setFormData(f=>({...f,password:e.target.value}))} onKeyDown={e=>e.key==="Enter"&&handleSignIn()}/>
          {formError && <p style={{fontSize:12,color:"#e05555",marginBottom:6,alignSelf:"flex-start"}}>{formError}</p>}
          <button style={mBtn} onClick={handleSignIn}>Sign in →</button>
          {divider}
          <GoogleBtn onClick={()=>setToast("Google auth needs a backend!")}/>
          <p style={{fontSize:12,color:C.muted,marginTop:14}}>No account? <span onClick={()=>{setModal("signup");setFormError("");setFormData({name:"",email:"",password:""});}} style={{color:C.muted2,textDecoration:"underline",cursor:"pointer"}}>Sign up</span></p>
        </ModalShell>
      )}

      {/* SIGN UP */}
      {modal==="signup" && (
        <ModalShell onClose={()=>setModal(null)}>
          {modalLogo}{modalTitle("Create account")}
          <p style={{fontSize:13,color:C.muted,marginBottom:20}}>Join Zyncc for free</p>
          <input type="text" placeholder="Full name" style={mInput} value={formData.name} onChange={e=>setFormData(f=>({...f,name:e.target.value}))}/>
          <input type="email" placeholder="Email address" style={mInput} value={formData.email} onChange={e=>setFormData(f=>({...f,email:e.target.value}))}/>
          <input type="password" placeholder="Password (6+ chars)" style={mInput} value={formData.password} onChange={e=>setFormData(f=>({...f,password:e.target.value}))} onKeyDown={e=>e.key==="Enter"&&handleSignUp()}/>
          {formError && <p style={{fontSize:12,color:"#e05555",marginBottom:6,alignSelf:"flex-start"}}>{formError}</p>}
          <button style={mBtn} onClick={handleSignUp}>Create account →</button>
          {divider}
          <GoogleBtn onClick={()=>setToast("Google auth needs a backend!")}/>
          <p style={{fontSize:12,color:C.muted,marginTop:14}}>Have an account? <span onClick={()=>{setModal("signin");setFormError("");setFormData({name:"",email:"",password:""});}} style={{color:C.muted2,textDecoration:"underline",cursor:"pointer"}}>Sign in</span></p>
        </ModalShell>
      )}

      {toast && (
        <div style={{position:"fixed",bottom:90,left:"50%",transform:"translateX(-50%)",background:C.bg3,border:"1px solid rgba(255,255,255,0.1)",color:C.muted2,padding:"9px 18px",borderRadius:10,fontSize:13,zIndex:300,whiteSpace:"nowrap",pointerEvents:"none"}}>{toast}</div>
      )}
    </div>
  );
}
